// ============ IN-MEMORY STORES ============
let orders: Order[] = [];
let escrows: Escrow[] = [];
let notifications: Notification[] = [];

// ============ ORDER HELPERS ============
export function getOrders(): Order[] { return orders; }
export function getOrderById(id: string): Order | undefined {
    return orders.find(o => o.id === id);
}
export function addOrder(order: Order): void {
    orders.push(order);
}
export function updateOrder(id: string, updates: Partial<Order>): Order | null {
    const idx = orders.findIndex(o => o.id === id);
    if (idx === -1) return null;
    orders[idx] = { ...orders[idx], ...updates, updatedAt: new Date().toISOString() };
    return orders[idx];
}

// ============ ESCROW HELPERS ============
export function getEscrowByOrderId(orderId: string): Escrow | undefined {
    return escrows.find(e => e.orderId === orderId);
}
export function addEscrow(escrow: Escrow): void {
    escrows.push(escrow);
}
export function updateEscrow(orderId: string, updates: Partial<Escrow>): Escrow | null {
    const idx = escrows.findIndex(e => e.orderId === orderId);
    if (idx === -1) return null;
    escrows[idx] = { ...escrows[idx], ...updates };
    return escrows[idx];
}

// ============ NOTIFICATION HELPERS ============
export function getNotifications(): Notification[] { return notifications; }
export function addNotification(n: Omit<Notification, 'id' | 'createdAt' | 'read'>): void {
    notifications.push({
        ...n,
        id: `notif_${Date.now()}_${Math.random().toString(36).slice(2)}`,
        createdAt: new Date().toISOString(),
        read: false,
    });
}
export function markNotificationRead(id: string): void {
    const n = notifications.find(n => n.id === id);
    if (n) n.read = true;
}

